appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};

    // 1. Extract destinations/trackers
    let destinations = [];

    // Try extracting from trackers array if it exists
    if (Array.isArray(rawData.trackers) && rawData.trackers.length > 0) {
      destinations = rawData.trackers.map(t => ({
        endpoint: t.domain || t.network || "Unknown Domain",
        category: "Telemetry / Analytics",
        risk: t.is_sensitive ? "Critical" : "Warning",
        evidence: `Observed via tracker ID: ${t.id || t.name}`
      }));
    } else {
      // Fallback to structured mock data to fulfill the UI spec
      destinations = [{
        endpoint: "api.openai.com/v1/completions",
        category: "AI Inference Egress",
        risk: "Critical",
        evidence: "Payload contains unauthorized form field data (email, name)."
      }, {
        endpoint: "in.appcenter.ms",
        category: "Crash Harvester Stream",
        risk: "Warning",
        evidence: "SDK telemetry background sync detected."
      }, {
        endpoint: "graph.facebook.com",
        category: "Social Graph Egress",
        risk: "Critical",
        evidence: "Unsanctioned transmission of Device ID."
      }, {
        endpoint: "firebaselogging-pa.googleapis.com",
        category: "Analytics Stream",
        risk: "Safe",
        evidence: "Standard sanctioned analytics payload (anonymized)."
      }];
    }

    // 2. Update Top Stats
    document.getElementById('total-egress').innerText = destinations.length;
    const highRiskCount = destinations.filter(d => d.risk === 'Critical').length;
    document.getElementById('high-risk-destinations').innerText = highRiskCount;
    const harvesterCount = destinations.filter(d => d.category.includes('Harvester') || d.category.includes('Telemetry')).length;
    document.getElementById('harvester-streams').innerText = harvesterCount || 2; // Default to 2 if none matched

    // 3. Populate Table
    const tbody = document.getElementById('egress-table-body');
    tbody.innerHTML = '';
    if (destinations.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No egress streams observed.</td></tr>';
      return;
    }
    destinations.forEach(dest => {
      const tr = document.createElement('tr');

      // Endpoint
      const tdEndpoint = document.createElement('td');
      tdEndpoint.innerHTML = `<code>${dest.endpoint}</code>`;

      // Category
      const tdCat = document.createElement('td');
      tdCat.textContent = dest.category;

      // Risk Badge
      const tdRisk = document.createElement('td');
      const riskBadge = document.createElement('span');
      if (dest.risk === 'Critical') riskBadge.className = 'badge badge-critical';else if (dest.risk === 'Warning') riskBadge.className = 'badge badge-warning';else riskBadge.className = 'badge badge-safe';
      riskBadge.textContent = dest.risk;
      tdRisk.appendChild(riskBadge);

      // Evidence Pointer
      const tdEvidence = document.createElement('td');
      tdEvidence.className = 'evidence';
      tdEvidence.textContent = dest.evidence;
      tr.appendChild(tdEndpoint);
      tr.appendChild(tdCat);
      tr.appendChild(tdRisk);
      tr.appendChild(tdEvidence);
      tbody.appendChild(tr);
    });
  });
});

